class NestedIterator {
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        stack<vector<NestedInteger>*> st;
        for (auto& ni : nestedList) {
            if (ni.isInteger()) {
                st.push(&ni);
            } else {
                st.push(&ni.getList());
            }
        }
        while (!st.empty()) {
            st_.push(st.top());
            st.pop();
        }
    }

    int next() {
        if (st_.empty()) return 0;
        NestedInteger* ni = st_.top();
        st_.pop();
        int res = ni->getInteger();
        if (!ni->isInteger()) {
            for (auto& n : ni->getList()) {
                st_.push(&n);
            }
        }
        return res;
    }

    bool hasNext() {
        return !st_.empty();
    }
private:
    stack<NestedInteger*> st_;
};
```
